PythonGAP <pre><code>from libsemigroups_pybind11 import Presentation, congruence_kind, ToddCoxeter
p = Presentation("az").contains_empty_word(True)
p.rules = ["a" * 2, "", "z" * 2, "z", "az" * 3 + "a", "zaz"]
tc = ToddCoxeter(congruence_kind.twosided, p)
tc.number_of_classes() # returns 7
</code></pre> <pre><code>F := FreeMonoid("a", "z");
AssignGeneratorVariables(F);;
R := [
       [a * a, One(F)],
       [z * z, z],
       [(a * z) ^ 3 * a, z * a * z]
     ];
S := F / R;
Size(S); # returns 7
</code></pre>

